   817→        // Reconstruct y from fitted values and residuals
   818→        let y_data: Vec<f64> = self.fitted_values.iter()
   819→            .zip(self.residuals.iter())
   820→            .map(|(fitted, resid)| fitted + resid)
   821→            .collect();
