  1103→/// Bootstrap statistic for linear models
  1104→struct LmBootstrapStatistic {
  1105→    n_params: usize,
  1106→}
  1107→
  1108→impl BootstrapStatistic for LmBootstrapStatistic {
  1109→    fn compute(&self, x: ArrayView2<f64>, y: ArrayView1<f64>) -> Array1<f64> {
  1110→        match Lm::fit_ndarray(x, y) {
  1111→            Ok(fit) => Array1::from(fit.coefficients().to_vec()),
  1112→            Err(_) => Array1::zeros(self.n_params), // Return zeros with consistent dimension
  1113→        }
  1114→    }
  1115→
  1116→    fn n_stats(&self) -> usize {
  1117→        self.n_params
  1118→    }
  1119→}
