  1121→/// Bootstrap statistic for generalized linear models
  1122→struct GlmBootstrapStatistic {
  1123→    n_params: usize,
  1124→    family: String,
  1125→}
  1126→
  1127→impl BootstrapStatistic for GlmBootstrapStatistic {
  1128→    fn compute(&self, x: ArrayView2<f64>, y: ArrayView1<f64>) -> Array1<f64> {
  1129→        // Use appropriate family based on stored family name
  1130→        // For now, default to Gaussian but this could be extended
  1131→        match &self.family[..] {
  1132→            "Gaussian" => match Glm::fit_ndarray(x, y, Gaussian, None, None) {
  1133→                Ok(fit) => Array1::from(fit.coefficients().to_vec()),
  1134→                Err(_) => Array1::zeros(self.n_params),
  1135→            },
  1136→            "Poisson" => match Glm::fit_ndarray(x, y, Poisson, None, None) {
  1137→                Ok(fit) => Array1::from(fit.coefficients().to_vec()),
  1138→                Err(_) => Array1::zeros(self.n_params),
  1139→            },
  1140→            _ => {
  1141→                // Default to Gaussian for unknown families
  1142→                match Glm::fit_ndarray(x, y, Gaussian, None, None) {
  1143→                    Ok(fit) => Array1::from(fit.coefficients().to_vec()),
  1144→                    Err(_) => Array1::zeros(self.n_params),
  1145→                }
  1146→            }
  1147→        }
  1148→    }
  1149→
  1150→    fn n_stats(&self) -> usize {
  1151→        self.n_params
  1152→    }
  1153→}
  1154→
  1155→/// Bootstrap statistic for regularized models
  1156→struct RegularizedBootstrapStatistic {
  1157→    lambda: f64,
  1158→    alpha: f64,
  1159→    n_params: usize,
  1160→}
  1161→
  1162→impl BootstrapStatistic for RegularizedBootstrapStatistic {
  1163→    fn compute(&self, x: ArrayView2<f64>, y: ArrayView1<f64>) -> Array1<f64> {
  1164→        let config = CoordinateDescentConfig {
  1165→            lambda: self.lambda,
  1166→            alpha: self.alpha,
  1167→            ..Default::default()
  1168→        };
  1169→
  1170→        match coordinate_descent(x, y, Some(config)) {
  1171→            Ok(result) => result.params,
  1172→            Err(_) => Array1::zeros(self.n_params), // Return zeros with consistent dimension
  1173→        }
  1174→    }
  1175→
  1176→    fn n_stats(&self) -> usize {
  1177→        self.n_params
  1178→    }
  1179→}
