    fn bootstrap(&self, n_samples: usize) -> Result<BootstrapResult, ModelError> {
        // Create bootstrap statistic that refits the regularized model
        let bootstrap_stat = RegularizedBootstrapStatistic {
            lambda: self.lambda,
            alpha: self.alpha,
