   515→    /// Parse R oracle output CSV into structured results
   516→    fn parse_r_output(file_path: &str) -> Result<RResults, Box<dyn std::error::Error>> {
   517→        let mut reader = ReaderBuilder::new().from_path(file_path)?;
   518→
   519→        let mut coefficients = Vec::new();
   520→        let mut residuals = Vec::new();
   521→        let mut fitted_values = Vec::new();
   522→
   523→        for result in reader.records() {
   524→            let record = result?;
   525→            let metric = &record[0];
   526→            let value_str = &record[1];
   527→            // Note: record[2] contains the index, but we don't need it
   528→
   529→            // Skip NA values from R
   530→            if value_str == "NA" {
   531→                continue;
   532→            }
   533→
   534→            let value: f64 = value_str.parse()?;
   535→
   536→            match metric {
   537→                "coefficients" => coefficients.push(value),
   538→                "residuals" => residuals.push(value),
   539→                "fitted_values" => fitted_values.push(value),
   540→                _ => {} // ignore other metrics for now
   541→            }
   542→        }
   543→
   544→        Ok(RResults {
   545→            coefficients,
   546→            residuals,
   547→            fitted_values,
   548→        })
   549→    }
