/// Provides confidence bands that cover the entire regression line
/// with the specified confidence level
pub fn working_hotelling_bands(
    x: &Mat<f64>,
    beta: &[f64],
    cov_beta: &Mat<f64>,
    sigma: f64,
    df: usize,
